import { Question } from "@/lib/types";

export const questions: Question[] = [
    { id: "y1ht2-001", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 01", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["one-tailed", "lower tail", "hypothesis test", "binomial"], questionText: "A manufacturer claims that 30% of items produced are defective. In a random sample of 10 items, only 1 is found to be defective. Under \\(H_0: p = 0.3\\), calculate \\(P(X \\le 1)\\) where \\(X \\sim B(10, 0.3)\\). Give your answer to 4 decimal places.", workedSolution: { steps: [{ stepNumber: 1, description: "Calculate P(X = 0).", workingLatex: "P(X = 0) = \\binom{10}{0}(0.3)^0(0.7)^{10} = 0.7^{10} = 0.0282", explanation: "0.7^10 = 0.0282475249, which rounds to 0.0282." }, { stepNumber: 2, description: "Calculate P(X = 1).", workingLatex: "P(X = 1) = \\binom{10}{1}(0.3)^1(0.7)^9 = 10 \\times 0.3 \\times 0.7^9 = 10 \\times 0.3 \\times 0.0404 = 0.1211", explanation: "0.7^9 = 0.04035360699, so 10 * 0.3 * 0.04035360699 = 0.1211." }, { stepNumber: 3, description: "Sum to find P(X <= 1).", workingLatex: "P(X \\le 1) = 0.0282 + 0.1211 = 0.1493", explanation: "" }], finalAnswer: "\\(P(X \\le 1) = 0.1493\\)." } },
    { id: "y1ht2-002", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 02", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["one-tailed", "lower tail", "hypothesis test", "binomial"], questionText: "A shop owner believes that 40% of customers buy a particular product. In a random sample of 8 customers, none buy the product. Test at the 5% significance level whether there is evidence that the proportion is less than 0.4. State \\(H_0\\), \\(H_1\\), calculate the relevant probability, and state your conclusion.", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.4 \\quad H_1: p < 0.4", explanation: "We are testing whether the proportion has decreased, so this is a one-tailed test." }, { stepNumber: 2, description: "Identify the distribution and calculate P(X = 0).", workingLatex: "X \\sim B(8, 0.4) \\quad P(X = 0) = 0.6^8 = 0.0168", explanation: "0.6^8 = 0.01679616." }, { stepNumber: 3, description: "Compare to the significance level and conclude.", workingLatex: "0.0168 < 0.05", explanation: "Since the probability is less than 0.05, we reject H_0." }], finalAnswer: "There is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the proportion of customers buying the product is less than 0.4." } },
    { id: "y1ht2-003", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 03", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["one-tailed", "upper tail", "hypothesis test", "binomial"], questionText: "A teacher claims that 20% of students pass a difficult test. After extra tuition, 5 out of 6 students pass. Test at the 5% significance level whether there is evidence that the pass rate has increased. Calculate \\(P(X \\ge 5)\\) where \\(X \\sim B(6, 0.2)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.2 \\quad H_1: p > 0.2", explanation: "We are testing whether the pass rate has increased." }, { stepNumber: 2, description: "Calculate P(X = 5).", workingLatex: "P(X = 5) = \\binom{6}{5}(0.2)^5(0.8)^1 = 6 \\times 0.00032 \\times 0.8 = 0.001536", explanation: "" }, { stepNumber: 3, description: "Calculate P(X = 6).", workingLatex: "P(X = 6) = \\binom{6}{6}(0.2)^6 = 0.000064", explanation: "" }, { stepNumber: 4, description: "Find P(X >= 5) and compare to 0.05.", workingLatex: "P(X \\ge 5) = 0.001536 + 0.000064 = 0.0016", explanation: "0.0016 < 0.05, so we reject H_0." }], finalAnswer: "\\(P(X \\ge 5) = 0.0016\\). Since \\(0.0016 < 0.05\\), there is sufficient evidence to reject \\(H_0\\). The data suggests the pass rate has increased." } },
    { id: "y1ht2-004", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 04", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["one-tailed", "upper tail", "coin", "hypothesis test", "binomial"], questionText: "A coin is tossed 10 times and 8 heads are observed. Test at the 5% significance level whether the coin is biased towards heads. State your hypotheses clearly.", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.5 \\quad H_1: p > 0.5", explanation: "p is the probability of heads. We are testing for bias towards heads." }, { stepNumber: 2, description: "Calculate P(X >= 8) where X ~ B(10, 0.5).", workingLatex: "P(X = 8) = \\binom{10}{8}(0.5)^{10} = 45 \\times \\frac{1}{1024} = 0.0439", explanation: "" }, { stepNumber: 3, description: "Calculate P(X = 9) and P(X = 10).", workingLatex: "P(X = 9) = \\binom{10}{9}(0.5)^{10} = 10 \\times \\frac{1}{1024} = 0.00977 \\quad P(X = 10) = \\frac{1}{1024} = 0.000977", explanation: "" }, { stepNumber: 4, description: "Sum and compare to significance level.", workingLatex: "P(X \\ge 8) = 0.0439 + 0.00977 + 0.000977 = 0.0547", explanation: "0.0547 > 0.05, so we do not reject H_0." }], finalAnswer: "\\(P(X \\ge 8) = 0.0547\\). Since \\(0.0547 > 0.05\\), there is insufficient evidence at the 5% level to conclude the coin is biased towards heads." } },
    { id: "y1ht2-005", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 05", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["one-tailed", "lower tail", "hypothesis test", "binomial"], questionText: "Under \\(H_0: p = 0.5\\), a fair coin is tossed 5 times and 0 heads are observed. Calculate \\(P(X = 0)\\) where \\(X \\sim B(5, 0.5)\\) and state whether this is significant at the 5% level for a one-tailed test (\\(H_1: p < 0.5\\)).", workedSolution: { steps: [{ stepNumber: 1, description: "Calculate P(X = 0).", workingLatex: "P(X = 0) = (0.5)^5 = 0.03125", explanation: "" }, { stepNumber: 2, description: "Compare to the significance level.", workingLatex: "0.03125 < 0.05", explanation: "The result is significant at the 5% level." }], finalAnswer: "\\(P(X = 0) = 0.03125\\). Since \\(0.03125 < 0.05\\), the result is significant at the 5% level." } },
    { id: "y1ht2-006", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 06", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["one-tailed", "upper tail", "hypothesis test", "binomial"], questionText: "It is claimed that 10% of a population are left-handed. In a random sample of 7 people, 4 are left-handed. Test at the 5% significance level whether the proportion of left-handed people is greater than 10%. Calculate \\(P(X \\ge 4)\\) where \\(X \\sim B(7, 0.1)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.1 \\quad H_1: p > 0.1", explanation: "" }, { stepNumber: 2, description: "Calculate P(X = 4), P(X = 5), P(X = 6), P(X = 7).", workingLatex: "P(X=4) = \\binom{7}{4}(0.1)^4(0.9)^3 = 35 \\times 0.0001 \\times 0.729 = 0.002552", explanation: "" }, { stepNumber: 3, description: "Calculate the remaining terms.", workingLatex: "P(X=5) = \\binom{7}{5}(0.1)^5(0.9)^2 = 21 \\times 0.00001 \\times 0.81 = 0.000170 \\quad P(X=6) = 7 \\times 0.000001 \\times 0.9 = 0.0000063 \\quad P(X=7) = 0.0000001", explanation: "" }, { stepNumber: 4, description: "Sum and compare.", workingLatex: "P(X \\ge 4) = 0.002552 + 0.000170 + 0.0000063 + 0.0000001 \\approx 0.0027", explanation: "0.0027 < 0.05." }], finalAnswer: "\\(P(X \\ge 4) \\approx 0.0027\\). Since \\(0.0027 < 0.05\\), there is sufficient evidence to reject \\(H_0\\). The data suggests the proportion of left-handed people is greater than 10%." } },
    { id: "y1ht2-007", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 07", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["one-tailed", "lower tail", "hypothesis test", "binomial"], questionText: "A company claims that 50% of its products are rated 'excellent' by customers. In a sample of 8 products, only 1 is rated 'excellent'. Test at the 5% significance level whether the proportion rated 'excellent' is less than 50%. Calculate \\(P(X \\le 1)\\) where \\(X \\sim B(8, 0.5)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.5 \\quad H_1: p < 0.5", explanation: "" }, { stepNumber: 2, description: "Calculate P(X = 0) and P(X = 1).", workingLatex: "P(X=0) = (0.5)^8 = 0.003906 \\quad P(X=1) = \\binom{8}{1}(0.5)^8 = 8 \\times 0.003906 = 0.03125", explanation: "" }, { stepNumber: 3, description: "Sum and compare.", workingLatex: "P(X \\le 1) = 0.003906 + 0.03125 = 0.03516", explanation: "0.03516 < 0.05." }], finalAnswer: "\\(P(X \\le 1) = 0.0352\\). Since \\(0.0352 < 0.05\\), there is sufficient evidence to reject \\(H_0\\). The data suggests fewer than 50% of products are rated 'excellent'." } },
    { id: "y1ht2-008", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 08", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["one-tailed", "lower tail", "hypothesis test", "binomial"], questionText: "A farmer claims that 25% of his hens lay eggs every day. A sample of 6 hens is taken, and none lay an egg on a given day. Test at the 5% level whether the proportion is less than 25%. Calculate \\(P(X = 0)\\) where \\(X \\sim B(6, 0.25)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.25 \\quad H_1: p < 0.25", explanation: "" }, { stepNumber: 2, description: "Calculate P(X = 0).", workingLatex: "P(X = 0) = (0.75)^6 = 0.1780", explanation: "0.75^6 = 0.177978515625." }, { stepNumber: 3, description: "Compare to the significance level.", workingLatex: "0.1780 > 0.05", explanation: "" }], finalAnswer: "\\(P(X = 0) = 0.1780\\). Since \\(0.1780 > 0.05\\), there is insufficient evidence to reject \\(H_0\\). The data does not suggest the proportion is less than 25%." } },
    { id: "y1ht2-009", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 09", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["one-tailed", "upper tail", "coin", "hypothesis test", "binomial"], questionText: "A coin is tossed 6 times and all 6 tosses result in heads. Test at the 1% significance level whether the coin is biased towards heads.", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.5 \\quad H_1: p > 0.5", explanation: "" }, { stepNumber: 2, description: "Calculate P(X = 6) where X ~ B(6, 0.5).", workingLatex: "P(X = 6) = (0.5)^6 = 0.015625", explanation: "" }, { stepNumber: 3, description: "Since we observe all 6 heads, P(X >= 6) = P(X = 6). Compare to 0.01.", workingLatex: "P(X \\ge 6) = 0.0156", explanation: "0.0156 > 0.01, so we do not reject H_0 at the 1% level." }], finalAnswer: "\\(P(X \\ge 6) = 0.0156\\). Since \\(0.0156 > 0.01\\), there is insufficient evidence at the 1% level to conclude the coin is biased towards heads." } },
    { id: "y1ht2-010", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 10", yearCreated: 2026, examStyle: false, marks: 3, difficulty: "Foundation", tags: ["one-tailed", "lower tail", "hypothesis test", "binomial"], questionText: "A driving school claims a 60% first-time pass rate. In a sample of 5 students, only 1 passes first time. Test at the 5% significance level whether the pass rate is lower than claimed. Calculate \\(P(X \\le 1)\\) where \\(X \\sim B(5, 0.6)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.6 \\quad H_1: p < 0.6", explanation: "" }, { stepNumber: 2, description: "Calculate P(X = 0) and P(X = 1).", workingLatex: "P(X=0) = (0.4)^5 = 0.01024 \\quad P(X=1) = \\binom{5}{1}(0.6)(0.4)^4 = 5 \\times 0.6 \\times 0.0256 = 0.0768", explanation: "" }, { stepNumber: 3, description: "Sum and compare.", workingLatex: "P(X \\le 1) = 0.01024 + 0.0768 = 0.0870", explanation: "0.0870 > 0.05." }], finalAnswer: "\\(P(X \\le 1) = 0.0870\\). Since \\(0.0870 > 0.05\\), there is insufficient evidence to reject \\(H_0\\). The data does not suggest the pass rate is lower than 60%." } },
    { id: "y1ht2-011", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 11", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["one-tailed", "lower tail", "hypothesis test", "context", "binomial"], questionText: "A seed company claims that 80% of its seeds germinate. A gardener plants 20 seeds and only 12 germinate. She wishes to test whether the germination rate is lower than claimed. Using the cumulative binomial table, \\(P(X \\le 12) = 0.0321\\) where \\(X \\sim B(20, 0.8)\\). Carry out the test at the 5% significance level.", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.8 \\quad H_1: p < 0.8", explanation: "Testing whether the germination rate is lower than 80%." }, { stepNumber: 2, description: "Identify the distribution and the test statistic.", workingLatex: "X \\sim B(20, 0.8) \\quad \\text{observed } x = 12", explanation: "Under H_0, X follows B(20, 0.8). We observed 12 successes." }, { stepNumber: 3, description: "Find the probability of a result this extreme or more extreme in the lower tail.", workingLatex: "P(X \\le 12) = 0.0321", explanation: "This is given from the cumulative binomial table." }, { stepNumber: 4, description: "Compare to the significance level and conclude in context.", workingLatex: "0.0321 < 0.05", explanation: "Reject H_0." }], finalAnswer: "Since \\(P(X \\le 12) = 0.0321 < 0.05\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the germination rate is lower than the claimed 80%." } },
    { id: "y1ht2-012", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 12", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["one-tailed", "upper tail", "hypothesis test", "context", "binomial"], questionText: "A company receives complaints about 5% of its deliveries. After a change in their delivery process, 4 out of 20 deliveries receive complaints. Test at the 5% significance level whether the complaint rate has increased. You are given that \\(P(X \\ge 4) = 0.0159\\) where \\(X \\sim B(20, 0.05)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.05 \\quad H_1: p > 0.05", explanation: "Testing whether the complaint rate has increased." }, { stepNumber: 2, description: "Identify the distribution.", workingLatex: "X \\sim B(20, 0.05) \\quad \\text{observed } x = 4", explanation: "" }, { stepNumber: 3, description: "Use the given probability.", workingLatex: "P(X \\ge 4) = 0.0159", explanation: "We need the upper tail probability since we are testing for an increase." }, { stepNumber: 4, description: "Compare and conclude.", workingLatex: "0.0159 < 0.05", explanation: "" }], finalAnswer: "Since \\(P(X \\ge 4) = 0.0159 < 0.05\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the complaint rate has increased from 5%." } },
    { id: "y1ht2-013", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 13", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["one-tailed", "lower tail", "hypothesis test", "context", "binomial"], questionText: "A doctor believes that a drug is effective for 70% of patients. In a clinical trial, 8 out of 15 patients respond to the drug. Test at the 5% significance level whether the drug is less effective than claimed. You are given \\(P(X \\le 8) = 0.1311\\) where \\(X \\sim B(15, 0.7)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.7 \\quad H_1: p < 0.7", explanation: "" }, { stepNumber: 2, description: "Identify the distribution.", workingLatex: "X \\sim B(15, 0.7) \\quad \\text{observed } x = 8", explanation: "" }, { stepNumber: 3, description: "Use the given cumulative probability.", workingLatex: "P(X \\le 8) = 0.1311", explanation: "" }, { stepNumber: 4, description: "Compare and conclude.", workingLatex: "0.1311 > 0.05", explanation: "" }], finalAnswer: "Since \\(P(X \\le 8) = 0.1311 > 0.05\\), there is insufficient evidence at the 5% level to reject \\(H_0\\). The data does not suggest the drug is less effective than 70%." } },
    { id: "y1ht2-014", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 14", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["one-tailed", "lower tail", "1% level", "hypothesis test", "binomial"], questionText: "A factory produces light bulbs with a claimed defect rate of 10%. In a sample of 20 bulbs, none are defective. Test at the 1% significance level whether the defect rate is lower than claimed. You are given \\(P(X = 0) = 0.1216\\) where \\(X \\sim B(20, 0.1)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.1 \\quad H_1: p < 0.1", explanation: "" }, { stepNumber: 2, description: "Identify the test probability.", workingLatex: "P(X \\le 0) = P(X = 0) = 0.1216", explanation: "The observed value is 0, so we need P(X <= 0)." }, { stepNumber: 3, description: "Compare to the 1% significance level.", workingLatex: "0.1216 > 0.01", explanation: "" }], finalAnswer: "Since \\(P(X = 0) = 0.1216 > 0.01\\), there is insufficient evidence at the 1% level to reject \\(H_0\\). The data does not suggest the defect rate is lower than 10%." } },
    { id: "y1ht2-015", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 15", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["two-tailed", "hypothesis test", "coin", "binomial"], questionText: "A coin is tossed 10 times and 9 heads are obtained. Test at the 5% significance level whether the coin is biased (in either direction). State your hypotheses and show your working.", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.5 \\quad H_1: p \\ne 0.5", explanation: "This is a two-tailed test since we are testing for bias in either direction." }, { stepNumber: 2, description: "Since this is two-tailed, compare to alpha/2 = 0.025. We observed 9 heads, which is in the upper tail.", workingLatex: "P(X \\ge 9) = P(X=9) + P(X=10) = \\binom{10}{9}(0.5)^{10} + (0.5)^{10} = \\frac{10 + 1}{1024} = \\frac{11}{1024} = 0.01074", explanation: "" }, { stepNumber: 3, description: "Compare to alpha/2 = 0.025.", workingLatex: "0.01074 < 0.025", explanation: "The result falls in the rejection region for the two-tailed test." }], finalAnswer: "\\(P(X \\ge 9) = 0.0107\\). Since \\(0.0107 < 0.025\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The coin appears to be biased." } },
    { id: "y1ht2-016", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 16", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["two-tailed", "hypothesis test", "context", "binomial"], questionText: "A manufacturer claims that 30% of items produced are premium quality. A quality controller inspects 20 items and finds that 10 are premium quality. Test at the 5% significance level whether the proportion of premium items differs from 30%. You are given \\(P(X \\ge 10) = 0.0480\\) where \\(X \\sim B(20, 0.3)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.3 \\quad H_1: p \\ne 0.3", explanation: "Two-tailed test since we test whether p differs from 0.3." }, { stepNumber: 2, description: "Since this is two-tailed, we compare to alpha/2 = 0.025. The observed value 10 is above the expected value 6, so we use the upper tail.", workingLatex: "P(X \\ge 10) = 0.0480", explanation: "" }, { stepNumber: 3, description: "Compare to alpha/2.", workingLatex: "0.0480 > 0.025", explanation: "" }], finalAnswer: "Since \\(P(X \\ge 10) = 0.0480 > 0.025\\), there is insufficient evidence at the 5% level to reject \\(H_0\\). The data does not suggest the proportion of premium items differs from 30%." } },
    { id: "y1ht2-017", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 17", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["one-tailed", "upper tail", "hypothesis test", "context", "binomial"], questionText: "A school claims that 15% of its students achieve an A* grade. This year, 7 out of 20 students achieve an A*. Test at the 5% significance level whether the proportion achieving A* has increased. You are given \\(P(X \\ge 7) = 0.0219\\) where \\(X \\sim B(20, 0.15)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.15 \\quad H_1: p > 0.15", explanation: "" }, { stepNumber: 2, description: "Identify the distribution and use the given probability.", workingLatex: "X \\sim B(20, 0.15) \\quad P(X \\ge 7) = 0.0219", explanation: "" }, { stepNumber: 3, description: "Compare and conclude.", workingLatex: "0.0219 < 0.05", explanation: "" }], finalAnswer: "Since \\(P(X \\ge 7) = 0.0219 < 0.05\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the proportion of students achieving A* has increased." } },
    { id: "y1ht2-018", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 18", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["one-tailed", "upper tail", "1% level", "hypothesis test", "binomial"], questionText: "A bakery believes that 20% of loaves are undercooked. After adjusting the oven, 8 out of 15 loaves are undercooked. Test at the 1% significance level whether the proportion of undercooked loaves has increased. You are given \\(P(X \\ge 8) = 0.0035\\) where \\(X \\sim B(15, 0.2)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.2 \\quad H_1: p > 0.2", explanation: "" }, { stepNumber: 2, description: "Use the given probability.", workingLatex: "P(X \\ge 8) = 0.0035", explanation: "" }, { stepNumber: 3, description: "Compare to the 1% level.", workingLatex: "0.0035 < 0.01", explanation: "" }], finalAnswer: "Since \\(P(X \\ge 8) = 0.0035 < 0.01\\), there is sufficient evidence at the 1% level to reject \\(H_0\\). The data suggests the proportion of undercooked loaves has increased." } },
    { id: "y1ht2-019", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 19", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["one-tailed", "lower tail", "hypothesis test", "context", "p-value", "binomial"], questionText: "A survey suggests that 45% of adults exercise regularly. A health authority surveys 20 adults in a particular town and finds that 5 exercise regularly. Test at the 5% significance level whether the proportion who exercise regularly in this town is lower than the national figure. You are given \\(P(X \\le 5) = 0.0553\\) where \\(X \\sim B(20, 0.45)\\). State the p-value of the test.", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.45 \\quad H_1: p < 0.45", explanation: "" }, { stepNumber: 2, description: "Identify the p-value.", workingLatex: "\\text{p-value} = P(X \\le 5) = 0.0553", explanation: "The p-value is the probability of obtaining a result at least as extreme as the observed value under H_0." }, { stepNumber: 3, description: "Compare to the significance level.", workingLatex: "0.0553 > 0.05", explanation: "" }], finalAnswer: "The p-value is \\(0.0553\\). Since \\(0.0553 > 0.05\\), there is insufficient evidence at the 5% level to reject \\(H_0\\). The data does not suggest the proportion exercising regularly in this town is lower than 45%." } },
    { id: "y1ht2-020", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 20", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["one-tailed", "upper tail", "hypothesis test", "context", "binomial"], questionText: "A website claims that 25% of visitors make a purchase. After a redesign, 9 out of 20 visitors make a purchase. Test at the 5% significance level whether the redesign has increased the purchase rate. You are given \\(P(X \\ge 9) = 0.0409\\) where \\(X \\sim B(20, 0.25)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.25 \\quad H_1: p > 0.25", explanation: "" }, { stepNumber: 2, description: "Use the given probability.", workingLatex: "P(X \\ge 9) = 0.0409", explanation: "" }, { stepNumber: 3, description: "Compare to 0.05 and conclude.", workingLatex: "0.0409 < 0.05", explanation: "" }], finalAnswer: "Since \\(P(X \\ge 9) = 0.0409 < 0.05\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the redesign has increased the purchase rate." } },
    { id: "y1ht2-021", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 21", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["two-tailed", "hypothesis test", "context", "binomial"], questionText: "A supermarket claims that 40% of customers use self-checkout. In a random sample of 15 customers, 2 use self-checkout. Test at the 5% significance level whether the proportion using self-checkout differs from 40%. You are given \\(P(X \\le 2) = 0.0271\\) where \\(X \\sim B(15, 0.4)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.4 \\quad H_1: p \\ne 0.4", explanation: "Two-tailed test." }, { stepNumber: 2, description: "The observed value 2 is below the expected value of 6, so use the lower tail. For a two-tailed test, compare to alpha/2 = 0.025.", workingLatex: "P(X \\le 2) = 0.0271", explanation: "" }, { stepNumber: 3, description: "Compare to alpha/2.", workingLatex: "0.0271 > 0.025", explanation: "" }], finalAnswer: "Since \\(P(X \\le 2) = 0.0271 > 0.025\\), there is insufficient evidence at the 5% level to reject \\(H_0\\). The data does not suggest the proportion using self-checkout differs from 40%." } },
    { id: "y1ht2-022", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 22", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["one-tailed", "lower tail", "hypothesis test", "context", "binomial"], questionText: "A charity claims that 35% of people donate when asked. A fundraiser approaches 18 people and 3 donate. Test at the 5% significance level whether the donation rate is lower than claimed. You are given \\(P(X \\le 3) = 0.0547\\) where \\(X \\sim B(18, 0.35)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.35 \\quad H_1: p < 0.35", explanation: "" }, { stepNumber: 2, description: "Use the given probability.", workingLatex: "P(X \\le 3) = 0.0547", explanation: "" }, { stepNumber: 3, description: "Compare to 0.05 and conclude.", workingLatex: "0.0547 > 0.05", explanation: "" }], finalAnswer: "Since \\(P(X \\le 3) = 0.0547 > 0.05\\), there is insufficient evidence at the 5% level to reject \\(H_0\\). The data does not suggest the donation rate is lower than 35%." } },
    { id: "y1ht2-023", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 23", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["one-tailed", "upper tail", "hypothesis test", "context", "binomial"], questionText: "An insurance company states that 10% of claims are fraudulent. An investigator examines 20 claims and finds that 5 are fraudulent. Test at the 5% significance level whether the fraud rate has increased. You are given \\(P(X \\ge 5) = 0.0433\\) where \\(X \\sim B(20, 0.1)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.1 \\quad H_1: p > 0.1", explanation: "" }, { stepNumber: 2, description: "Use the given probability.", workingLatex: "P(X \\ge 5) = 0.0433", explanation: "" }, { stepNumber: 3, description: "Compare and conclude.", workingLatex: "0.0433 < 0.05", explanation: "" }], finalAnswer: "Since \\(P(X \\ge 5) = 0.0433 < 0.05\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the fraud rate has increased from 10%." } },
    { id: "y1ht2-024", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 24", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["two-tailed", "hypothesis test", "context", "binomial"], questionText: "A dice manufacturer claims their dice are fair, with \\(P(6) = \\frac{1}{6}\\). A die is rolled 18 times and a 6 appears 7 times. Test at the 5% significance level whether the die is biased with respect to the probability of rolling a 6. You are given \\(P(X \\ge 7) = 0.0135\\) where \\(X \\sim B(18, \\frac{1}{6})\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = \\tfrac{1}{6} \\quad H_1: p \\ne \\tfrac{1}{6}", explanation: "Two-tailed test." }, { stepNumber: 2, description: "The observed value 7 is above the expected value of 3, so we examine the upper tail. For a two-tailed test, compare to alpha/2 = 0.025.", workingLatex: "P(X \\ge 7) = 0.0135", explanation: "" }, { stepNumber: 3, description: "Compare to alpha/2.", workingLatex: "0.0135 < 0.025", explanation: "" }], finalAnswer: "Since \\(P(X \\ge 7) = 0.0135 < 0.025\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the die is biased with respect to rolling a 6." } },
    { id: "y1ht2-025", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 25", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["one-tailed", "lower tail", "hypothesis test", "context", "binomial"], questionText: "A phone company claims that 90% of calls are connected on the first attempt. A customer makes 15 calls and only 11 connect on the first attempt. Test at the 5% significance level whether the connection rate is lower than claimed. You are given \\(P(X \\le 11) = 0.0556\\) where \\(X \\sim B(15, 0.9)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.9 \\quad H_1: p < 0.9", explanation: "" }, { stepNumber: 2, description: "Use the given probability.", workingLatex: "P(X \\le 11) = 0.0556", explanation: "" }, { stepNumber: 3, description: "Compare to 0.05 and conclude.", workingLatex: "0.0556 > 0.05", explanation: "" }], finalAnswer: "Since \\(P(X \\le 11) = 0.0556 > 0.05\\), there is insufficient evidence at the 5% level to reject \\(H_0\\). The data does not suggest the connection rate is lower than 90%." } },
    { id: "y1ht2-026", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 26", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["one-tailed", "upper tail", "hypothesis test", "context", "compare levels", "binomial"], questionText: "A restaurant claims that 20% of meals are returned by customers. After changing supplier, 8 out of 18 meals are returned. Test at the 5% significance level whether the return rate has increased. You are given \\(P(X \\ge 8) = 0.0163\\) where \\(X \\sim B(18, 0.2)\\). Would the conclusion change at the 1% significance level?", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.2 \\quad H_1: p > 0.2", explanation: "" }, { stepNumber: 2, description: "Use the given probability.", workingLatex: "P(X \\ge 8) = 0.0163", explanation: "" }, { stepNumber: 3, description: "Compare to 0.05.", workingLatex: "0.0163 < 0.05 \\quad \\Rightarrow \\quad \\text{Reject } H_0 \\text{ at 5\% level.}", explanation: "" }, { stepNumber: 4, description: "Compare to 0.01.", workingLatex: "0.0163 > 0.01 \\quad \\Rightarrow \\quad \\text{Do not reject } H_0 \\text{ at 1\% level.}", explanation: "" }], finalAnswer: "At the 5% level, \\(0.0163 < 0.05\\), so there is sufficient evidence to reject \\(H_0\\). At the 1% level, \\(0.0163 > 0.01\\), so there is insufficient evidence. The conclusion changes between the two levels." } },
    { id: "y1ht2-027", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 27", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Standard", tags: ["one-tailed", "lower tail", "hypothesis test", "context", "binomial"], questionText: "A manufacturer claims that 75% of its products pass quality control. In a sample of 12 products, 7 pass. Test at the 5% significance level whether the pass rate is lower than claimed. You are given \\(P(X \\le 7) = 0.1576\\) where \\(X \\sim B(12, 0.75)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.75 \\quad H_1: p < 0.75", explanation: "" }, { stepNumber: 2, description: "Use the given probability.", workingLatex: "P(X \\le 7) = 0.1576", explanation: "" }, { stepNumber: 3, description: "Compare and conclude.", workingLatex: "0.1576 > 0.05", explanation: "" }], finalAnswer: "Since \\(P(X \\le 7) = 0.1576 > 0.05\\), there is insufficient evidence at the 5% level to reject \\(H_0\\). The data does not suggest the pass rate is lower than 75%." } },
    { id: "y1ht2-028", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 28", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Standard", tags: ["two-tailed", "hypothesis test", "context", "p-value", "binomial"], questionText: "A company claims that 50% of job applicants are shortlisted. In a sample of 16 applicants, 12 are shortlisted. Test at the 5% significance level whether the shortlisting rate differs from 50%. You are given \\(P(X \\ge 12) = 0.0384\\) where \\(X \\sim B(16, 0.5)\\). State the p-value of the test.", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.5 \\quad H_1: p \\ne 0.5", explanation: "Two-tailed test." }, { stepNumber: 2, description: "Identify the tail. The observed value 12 is above the expected value 8, so we use the upper tail.", workingLatex: "P(X \\ge 12) = 0.0384", explanation: "" }, { stepNumber: 3, description: "For a two-tailed test, the p-value is doubled.", workingLatex: "\\text{p-value} = 2 \\times 0.0384 = 0.0768", explanation: "We double because of symmetry considerations in a two-tailed test." }, { stepNumber: 4, description: "Compare to alpha = 0.05.", workingLatex: "0.0768 > 0.05", explanation: "Equivalently, 0.0384 > 0.025 = alpha/2." }], finalAnswer: "The p-value is \\(0.0768\\). Since \\(0.0768 > 0.05\\), there is insufficient evidence at the 5% level to reject \\(H_0\\). The data does not suggest the shortlisting rate differs from 50%." } },
    { id: "y1ht2-029", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 29", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["multi-part", "one-tailed", "compare levels", "hypothesis test", "context", "binomial"], questionText: "A politician claims that 60% of voters support a policy. A journalist surveys 20 voters and finds that 8 support the policy. (a) State suitable hypotheses to test whether the level of support is lower than claimed. (b) You are given \\(P(X \\le 8) = 0.0565\\) where \\(X \\sim B(20, 0.6)\\). Carry out the test at the 5% significance level. (c) State the conclusion at the 10% significance level. (d) Explain why the conclusions differ.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) State the hypotheses.", workingLatex: "H_0: p = 0.6 \\quad H_1: p < 0.6", explanation: "" }, { stepNumber: 2, description: "(b) Compare to 5% level.", workingLatex: "P(X \\le 8) = 0.0565 > 0.05", explanation: "Do not reject H_0 at the 5% level." }, { stepNumber: 3, description: "(c) Compare to 10% level.", workingLatex: "P(X \\le 8) = 0.0565 < 0.10", explanation: "Reject H_0 at the 10% level." }, { stepNumber: 4, description: "(d) Explain the difference.", workingLatex: "\\text{The p-value } 0.0565 \\text{ lies between } 0.05 \\text{ and } 0.10.", explanation: "At the 10% level, we allow a higher chance of incorrectly rejecting H_0 (Type I error), so more results are considered significant. The p-value falls between the two thresholds, leading to different conclusions." }], finalAnswer: "(a) \\(H_0: p = 0.6\\), \\(H_1: p < 0.6\\). (b) Since \\(0.0565 > 0.05\\), do not reject \\(H_0\\) at 5%. (c) Since \\(0.0565 < 0.10\\), reject \\(H_0\\) at 10%. (d) The p-value lies between 0.05 and 0.10, so the result is significant at the less stringent 10% level but not at the 5% level." } },
    { id: "y1ht2-030", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 30", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["two-tailed", "hypothesis test", "context", "binomial"], questionText: "A machine is set to produce 35% of items in colour A and 65% in colour B. After maintenance, a sample of 20 items contains 12 in colour A. Test at the 5% significance level whether the proportion of colour A items has changed. You are given \\(P(X \\ge 12) = 0.0105\\) and \\(P(X \\le 3) = 0.0444\\) where \\(X \\sim B(20, 0.35)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0: p = 0.35 \\quad H_1: p \\ne 0.35", explanation: "Two-tailed test." }, { stepNumber: 2, description: "The observed value 12 is above the expected value 7, so test in the upper tail. For a two-tailed test, compare to alpha/2 = 0.025.", workingLatex: "P(X \\ge 12) = 0.0105", explanation: "" }, { stepNumber: 3, description: "Compare to alpha/2.", workingLatex: "0.0105 < 0.025", explanation: "Reject H_0." }], finalAnswer: "Since \\(P(X \\ge 12) = 0.0105 < 0.025\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the proportion of colour A items has changed from 35%." } },
    { id: "y1ht2-031", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 31", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["p-value", "interpret", "hypothesis test", "binomial"], questionText: "A researcher conducts a one-tailed hypothesis test for a binomial parameter. The probability of obtaining a result at least as extreme as the observed value is 0.038. (a) State the conclusion at the 5% significance level. (b) State the conclusion at the 1% significance level. (c) Explain the meaning of 'the probability of obtaining a result at least as extreme as the observed value'.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Compare p-value to 5%.", workingLatex: "0.038 < 0.05", explanation: "Reject H_0 at the 5% level." }, { stepNumber: 2, description: "(b) Compare p-value to 1%.", workingLatex: "0.038 > 0.01", explanation: "Do not reject H_0 at the 1% level." }, { stepNumber: 3, description: "(c) Explain the p-value.", workingLatex: "\\text{p-value} = 0.038", explanation: "This means that if H_0 were true, the probability of observing a test statistic as extreme as (or more extreme than) what was actually observed is 3.8%. It measures the strength of evidence against H_0." }], finalAnswer: "(a) Since \\(0.038 < 0.05\\), reject \\(H_0\\) at the 5% level. There is sufficient evidence against \\(H_0\\). (b) Since \\(0.038 > 0.01\\), do not reject \\(H_0\\) at the 1% level. There is insufficient evidence. (c) The p-value is the probability, assuming \\(H_0\\) is true, of observing a result at least as extreme as the one obtained. A small p-value provides evidence against \\(H_0\\)." } },
    { id: "y1ht2-032", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 32", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["determine tail", "hypothesis test", "context", "binomial"], questionText: "A doctor claims that a treatment is effective for 55% of patients. After modifying the dosage, a trial of 18 patients is conducted and 14 respond positively. (a) Explain whether a one-tailed or two-tailed test is appropriate if the doctor wants to know whether the effectiveness has changed. (b) Carry out the appropriate test at the 5% significance level. You are given \\(P(X \\ge 14) = 0.0338\\) where \\(X \\sim B(18, 0.55)\\).", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Determine the type of test.", workingLatex: "H_0: p = 0.55 \\quad H_1: p \\ne 0.55", explanation: "Since the doctor wants to know whether effectiveness has changed (not specifically increased or decreased), a two-tailed test is appropriate." }, { stepNumber: 2, description: "(b) The observed value 14 is above the expected value 9.9, so test in the upper tail. Compare to alpha/2 = 0.025.", workingLatex: "P(X \\ge 14) = 0.0338", explanation: "" }, { stepNumber: 3, description: "Compare to alpha/2.", workingLatex: "0.0338 > 0.025", explanation: "" }], finalAnswer: "(a) A two-tailed test is appropriate because the doctor wants to detect a change in either direction. (b) Since \\(P(X \\ge 14) = 0.0338 > 0.025\\), there is insufficient evidence at the 5% level to reject \\(H_0\\). The data does not suggest the effectiveness has changed from 55%." } },
    { id: "y1ht2-033", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 33", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["multi-part", "two-tailed", "hypothesis test", "context", "binomial"], questionText: "A factory produces bolts where historically 15% are oversized. A new machine is installed and a sample of 20 bolts is tested. (a) State hypotheses to test whether the proportion of oversized bolts has changed. (b) If 0 bolts are oversized, carry out the test at the 5% level. You are given \\(P(X = 0) = 0.0388\\) where \\(X \\sim B(20, 0.15)\\). (c) Would the conclusion change at the 10% level?", workedSolution: { steps: [{ stepNumber: 1, description: "(a) State hypotheses.", workingLatex: "H_0: p = 0.15 \\quad H_1: p \\ne 0.15", explanation: "Two-tailed test since we test for any change." }, { stepNumber: 2, description: "(b) The observed value 0 is in the lower tail. For a two-tailed test, compare to alpha/2 = 0.025.", workingLatex: "P(X \\le 0) = P(X = 0) = 0.0388", explanation: "" }, { stepNumber: 3, description: "Compare to alpha/2 = 0.025 at the 5% level.", workingLatex: "0.0388 > 0.025", explanation: "Do not reject H_0 at the 5% level." }, { stepNumber: 4, description: "(c) At the 10% level, compare to alpha/2 = 0.05.", workingLatex: "0.0388 < 0.05", explanation: "Reject H_0 at the 10% level." }], finalAnswer: "(a) \\(H_0: p = 0.15\\), \\(H_1: p \\ne 0.15\\). (b) Since \\(0.0388 > 0.025\\), do not reject \\(H_0\\) at the 5% level. (c) Since \\(0.0388 < 0.05\\), reject \\(H_0\\) at the 10% level. The conclusion changes." } },
    { id: "y1ht2-034", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 34", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["show that", "exact calculation", "hypothesis test", "binomial"], questionText: "Let \\(X \\sim B(8, 0.5)\\). (a) Show that \\(P(X \\ge 7) = 0.03516\\) (to 5 significant figures). (b) A coin is tossed 8 times and 7 heads are obtained. Using part (a), test at the 5% significance level whether the coin is biased towards heads.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Calculate P(X = 7).", workingLatex: "P(X=7) = \\binom{8}{7}(0.5)^8 = 8 \\times \\frac{1}{256} = \\frac{8}{256} = 0.03125", explanation: "" }, { stepNumber: 2, description: "Calculate P(X = 8).", workingLatex: "P(X=8) = (0.5)^8 = \\frac{1}{256} = 0.003906", explanation: "" }, { stepNumber: 3, description: "Sum.", workingLatex: "P(X \\ge 7) = 0.03125 + 0.003906 = 0.035156 \\approx 0.03516", explanation: "As required." }, { stepNumber: 4, description: "(b) State hypotheses and test.", workingLatex: "H_0: p = 0.5 \\quad H_1: p > 0.5 \\quad P(X \\ge 7) = 0.03516 < 0.05", explanation: "Reject H_0." }], finalAnswer: "(a) \\(P(X \\ge 7) = \\frac{8}{256} + \\frac{1}{256} = \\frac{9}{256} = 0.03516\\) as required. (b) Since \\(0.03516 < 0.05\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the coin is biased towards heads." } },
    { id: "y1ht2-035", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 35", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["larger n", "cumulative table", "hypothesis test", "context", "binomial"], questionText: "A health authority claims that 30% of adults in a region are overweight. A researcher surveys 20 adults and finds 10 are overweight. (a) Test at the 5% significance level whether the proportion of overweight adults has increased. You are given \\(P(X \\ge 10) = 0.0480\\) where \\(X \\sim B(20, 0.3)\\). (b) State the conclusion at the 1% level.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) State hypotheses.", workingLatex: "H_0: p = 0.3 \\quad H_1: p > 0.3", explanation: "" }, { stepNumber: 2, description: "Compare to 0.05.", workingLatex: "P(X \\ge 10) = 0.0480 < 0.05", explanation: "Reject H_0 at the 5% level." }, { stepNumber: 3, description: "(b) Compare to 0.01.", workingLatex: "0.0480 > 0.01", explanation: "Do not reject H_0 at the 1% level." }], finalAnswer: "(a) Since \\(P(X \\ge 10) = 0.0480 < 0.05\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the proportion of overweight adults has increased. (b) Since \\(0.0480 > 0.01\\), there is insufficient evidence at the 1% level. The conclusion changes." } },
    { id: "y1ht2-036", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 36", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["show that", "exact calculation", "hypothesis test", "context", "binomial"], questionText: "A company claims that 20% of emails it sends are opened by recipients. In a sample of 15 emails, 7 are opened. (a) Show that \\(P(X \\ge 7) = 0.0181\\) (to 3 significant figures) where \\(X \\sim B(15, 0.2)\\). You may use: \\(P(X \\le 6) = 0.9819\\). (b) Test at the 5% significance level whether the open rate has increased.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Use the complement.", workingLatex: "P(X \\ge 7) = 1 - P(X \\le 6) = 1 - 0.9819 = 0.0181", explanation: "As required." }, { stepNumber: 2, description: "(b) State hypotheses.", workingLatex: "H_0: p = 0.2 \\quad H_1: p > 0.2", explanation: "" }, { stepNumber: 3, description: "Compare to 0.05.", workingLatex: "0.0181 < 0.05", explanation: "Reject H_0." }], finalAnswer: "(a) \\(P(X \\ge 7) = 1 - 0.9819 = 0.0181\\) as required. (b) Since \\(0.0181 < 0.05\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the email open rate has increased from 20%." } },
    { id: "y1ht2-037", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 37", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Challenge", tags: ["multi-part", "exact calculation", "compare levels", "hypothesis test", "context", "binomial"], questionText: "A seed packet states that 85% of seeds germinate. A gardener plants 16 seeds and only 10 germinate. (a) State suitable hypotheses to test whether the germination rate is lower than stated. (b) Calculate \\(P(X \\le 10)\\) where \\(X \\sim B(16, 0.85)\\). You are given \\(P(X \\le 10) = 0.0170\\). (c) Carry out the test at the 5% level. (d) Carry out the test at the 1% level. (e) Comment on the difference.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) State hypotheses.", workingLatex: "H_0: p = 0.85 \\quad H_1: p < 0.85", explanation: "" }, { stepNumber: 2, description: "(b) Use the given value.", workingLatex: "P(X \\le 10) = 0.0170", explanation: "This is the probability of obtaining 10 or fewer germinated seeds out of 16 when p = 0.85." }, { stepNumber: 3, description: "(c) Compare to 0.05.", workingLatex: "0.0170 < 0.05", explanation: "Reject H_0 at the 5% level." }, { stepNumber: 4, description: "(d) Compare to 0.01.", workingLatex: "0.0170 > 0.01", explanation: "Do not reject H_0 at the 1% level." }, { stepNumber: 5, description: "(e) Comment.", workingLatex: "0.01 < 0.0170 < 0.05", explanation: "The p-value lies between the two significance levels, so the test is significant at 5% but not at 1%." }], finalAnswer: "(a) \\(H_0: p = 0.85\\), \\(H_1: p < 0.85\\). (b) \\(P(X \\le 10) = 0.0170\\). (c) Reject \\(H_0\\) at 5% since \\(0.0170 < 0.05\\). (d) Do not reject \\(H_0\\) at 1% since \\(0.0170 > 0.01\\). (e) The p-value falls between the two thresholds: a stricter significance level requires stronger evidence, which this sample does not provide." } },
    { id: "y1ht2-038", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 38", yearCreated: 2026, examStyle: true, marks: 7, difficulty: "Challenge", tags: ["two-tailed", "exact calculation", "hypothesis test", "context", "binomial"], questionText: "A bus company claims that 40% of buses arrive on time. A commuter records 20 bus arrivals and finds that 3 arrive on time. (a) Test at the 5% significance level whether the proportion of on-time buses differs from 40%. You are given \\(P(X \\le 3) = 0.0160\\) where \\(X \\sim B(20, 0.4)\\). (b) State the p-value of this two-tailed test.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) State hypotheses.", workingLatex: "H_0: p = 0.4 \\quad H_1: p \\ne 0.4", explanation: "Two-tailed test." }, { stepNumber: 2, description: "The observed value 3 is below the expected value 8, so test in the lower tail. Compare to alpha/2 = 0.025.", workingLatex: "P(X \\le 3) = 0.0160", explanation: "" }, { stepNumber: 3, description: "Compare to alpha/2.", workingLatex: "0.0160 < 0.025", explanation: "Reject H_0." }, { stepNumber: 4, description: "(b) The p-value for a two-tailed test.", workingLatex: "\\text{p-value} = 2 \\times 0.0160 = 0.0320", explanation: "We double the one-tail probability for the two-tailed p-value." }], finalAnswer: "(a) Since \\(P(X \\le 3) = 0.0160 < 0.025\\), there is sufficient evidence at the 5% level to reject \\(H_0\\). The data suggests the proportion of on-time buses differs from 40%. (b) The p-value is \\(0.0320\\)." } },
    { id: "y1ht2-039", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 39", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Challenge", tags: ["multi-part", "show that", "exact calculation", "hypothesis test", "binomial"], questionText: "Let \\(X \\sim B(10, 0.3)\\). (a) Show that \\(P(X = 0) = 0.0282\\) to 3 significant figures. (b) Show that \\(P(X \\le 0) = 0.0282\\) and hence determine whether observing \\(X = 0\\) would lead to rejection of \\(H_0: p = 0.3\\) in favour of \\(H_1: p < 0.3\\) at the 5% significance level. (c) Find \\(P(X \\le 1)\\), given \\(P(X = 1) = 0.1211\\), and determine whether observing \\(X = 1\\) would lead to rejection of \\(H_0\\) at the 5% level.", workedSolution: { steps: [{ stepNumber: 1, description: "(a) Calculate P(X = 0).", workingLatex: "P(X = 0) = \\binom{10}{0}(0.3)^0(0.7)^{10} = 0.7^{10} = 0.0282475...", explanation: "Rounds to 0.0282 to 3 significant figures, as required." }, { stepNumber: 2, description: "(b) Determine whether X = 0 leads to rejection.", workingLatex: "P(X \\le 0) = P(X = 0) = 0.0282 < 0.05", explanation: "Yes, observing X = 0 leads to rejection of H_0 at the 5% level." }, { stepNumber: 3, description: "(c) Find P(X <= 1).", workingLatex: "P(X \\le 1) = P(X = 0) + P(X = 1) = 0.0282 + 0.1211 = 0.1493", explanation: "" }, { stepNumber: 4, description: "Determine whether X = 1 leads to rejection.", workingLatex: "P(X \\le 1) = 0.1493 > 0.05", explanation: "No, observing X = 1 does not lead to rejection of H_0 at the 5% level." }], finalAnswer: "(a) \\(P(X = 0) = 0.7^{10} = 0.0282\\) as required. (b) Since \\(0.0282 < 0.05\\), \\(X = 0\\) lies in the critical region; reject \\(H_0\\). (c) \\(P(X \\le 1) = 0.1493 > 0.05\\), so \\(X = 1\\) does not lie in the critical region; do not reject \\(H_0\\)." } },
    { id: "y1ht2-040", topicRef: "y1ht2", topicTitle: "Binomial Hypothesis Tests 40", yearCreated: 2026, examStyle: true, marks: 8, difficulty: "Challenge", tags: ["multi-part", "two-tailed", "compare levels", "hypothesis test", "context", "binomial"], questionText: "A manufacturer claims that 50% of customers prefer product A over product B. A market researcher surveys 18 customers and finds that 13 prefer product A. (a) State hypotheses to test whether the preference differs from 50%. (b) You are given \\(P(X \\ge 13) = 0.0481\\) where \\(X \\sim B(18, 0.5)\\). Carry out the test at the 10% significance level. (c) Carry out the test at the 5% significance level. (d) A colleague argues that a one-tailed test should be used. If \\(H_1: p > 0.5\\), state the conclusion at the 5% level and explain why it differs from part (c).", workedSolution: { steps: [{ stepNumber: 1, description: "(a) State hypotheses.", workingLatex: "H_0: p = 0.5 \\quad H_1: p \\ne 0.5", explanation: "Two-tailed test for whether the preference differs from 50%." }, { stepNumber: 2, description: "(b) At the 10% level, compare to alpha/2 = 0.05.", workingLatex: "P(X \\ge 13) = 0.0481 < 0.05", explanation: "Reject H_0 at the 10% level." }, { stepNumber: 3, description: "(c) At the 5% level, compare to alpha/2 = 0.025.", workingLatex: "P(X \\ge 13) = 0.0481 > 0.025", explanation: "Do not reject H_0 at the 5% level." }, { stepNumber: 4, description: "(d) For a one-tailed test with H_1: p > 0.5, compare P(X >= 13) directly to alpha = 0.05.", workingLatex: "H_0: p = 0.5 \\quad H_1: p > 0.5 \\quad P(X \\ge 13) = 0.0481 < 0.05", explanation: "Reject H_0 at the 5% level with the one-tailed test." }, { stepNumber: 5, description: "Explain the difference.", workingLatex: "\\text{One-tailed: compare to } \\alpha = 0.05. \\quad \\text{Two-tailed: compare to } \\frac{\\alpha}{2} = 0.025.", explanation: "A one-tailed test places all of the significance level in one tail, making it easier to reject H_0 in that direction. A two-tailed test splits alpha between both tails, requiring stronger evidence in each tail to reject H_0." }], finalAnswer: "(a) \\(H_0: p = 0.5\\), \\(H_1: p \\ne 0.5\\). (b) At 10%: \\(0.0481 < 0.05\\), reject \\(H_0\\). (c) At 5%: \\(0.0481 > 0.025\\), do not reject \\(H_0\\). (d) One-tailed at 5%: \\(0.0481 < 0.05\\), reject \\(H_0\\). The one-tailed test rejects because it compares to \\(\\alpha = 0.05\\) rather than \\(\\alpha/2 = 0.025\\)." } },
];
